351	void AMDGPUIntrinsic::DeclareModules(mlir::ModuleOp module) {
352	    if (!module)
353	        return;
354	
355	    // Register the bytecode in the intrinsic registry
356	    auto libraryBytes = GetAmdgpuIntrinsicLibrary();
357	    auto &registry = utils::EmbeddedFilesystemView::getInstance();
358	    registry.registerFile(std::string(kAmdgpuIntrinsicLibraryName),
359	                          libraryBytes);
360	
361	    intrinsics::GetOrCreateImplementationContainer(module, "amdgpu",
362	                                                   kAmdgpuIntrinsicLibraryTag);
363	
364	    auto loadDialects = [](mlir::MLIRContext *ctx) {
365	        ctx->loadDialect<mlir::arith::ArithDialect, mlir::func::FuncDialect,
366	                         mlir::vector::VectorDialect, mlir::LLVM::LLVMDialect,
367	                         mlir::ROCDL::ROCDLDialect, cf::SubstrateDialect>();
368	    };
369	
370	    if (failed(intrinsics::EnsureIntrinsicDeclarations(
371	            module, kAmdgpuIntrinsicLibraryName, libraryBytes, loadDialects))) {
372	        module.emitError() << "failed to declare AMDGPU intrinsics";
373	    }
374	}
