377	mlir::Type GetMfmaElemType(amdgpu_mfma::VectorElemKind kind,
378	                           mlir::OpBuilder &builder) {
379	    switch (kind) {
380	    case amdgpu_mfma::VectorElemKind::I32:
381	        return builder.getI32Type();
382	    case amdgpu_mfma::VectorElemKind::F16:
383	        return builder.getF16Type();
384	    case amdgpu_mfma::VectorElemKind::F32:
385	        return builder.getF32Type();
386	    case amdgpu_mfma::VectorElemKind::BF16:
387	        return builder.getBF16Type();
388	    }
389	    llvm_unreachable("Unsupported MFMA element kind");
390	}
391	
392	mlir::Value ConvertToI32(mlir::OpBuilder &builder, mlir::Location location,
393	                         mlir::Value value) {
394	    if (value.getType().isIndex()) {
395	        return builder.create<mlir::arith::IndexCastOp>(
396	            location, builder.getI32Type(), value);
397	    }
398	
399	    auto intType = mlir::dyn_cast<mlir::IntegerType>(value.getType());
400	    if (!intType || intType.getWidth() == 32) {
401	        return value;
402	    }
403	    if (intType.getWidth() < 32) {
404	        return builder.create<mlir::arith::ExtUIOp>(
405	            location, builder.getI32Type(), value);
406	    }
407	    return builder.create<mlir::arith::TruncIOp>(location, builder.getI32Type(),
408	                                                 value);
409	}
410	
411	mlir::Value ConvertToIndex(mlir::OpBuilder &builder, mlir::Location location,
412	                           mlir::Value value) {
413	    if (value.getType().isIndex()) {
414	        return value;
415	    }
416	    auto intType = mlir::dyn_cast<mlir::IntegerType>(value.getType());
417	    if (!intType) {
418	        return value;
419	    }
420	    return builder.create<mlir::arith::IndexCastOp>(
421	        location, builder.getIndexType(), value);
422	}
