425	mlir::Value AMDGPUIntrinsic::CreateGenericMFMAFunction(
426	    ast::Call *call_expr, GeneratorContext *ctx,
427	    llvm::ArrayRef<mlir::Value> resolved_args,
428	    const amdgpu_mfma::MFMAConfig &config) const {
429	    auto &builder = ctx->GetCurrentFunctionGenerator()->GetBuilder();
430	    auto location = GetCallLocation(ctx, call_expr);
431	
432	    auto a = resolved_args[0];
433	    auto b = resolved_args[1];
434	    auto c = resolved_args[2];
435	
436	    auto type_a = GetMfmaElemType(config.aElem, builder);
437	    auto type_c = GetMfmaElemType(config.cElem, builder);
438	
439	    int64_t c_elements = config.GetCElementCount();
440	    auto result_vector_type = mlir::VectorType::get({c_elements}, type_c);
441	
442	    // Convert MLIR types to string representations for attributes
443	    std::string type_a_str, type_c_str;
444	    llvm::raw_string_ostream type_a_stream(type_a_str);
445	    llvm::raw_string_ostream type_c_stream(type_c_str);
446	
447	    if (type_a.isF16()) {
448	        type_a_stream << "f16";
449	    } else if (type_a.isBF16()) {
450	        type_a_stream << "bf16";
451	    } else if (type_a.isF32()) {
452	        type_a_stream << "f32";
453	    } else if (type_a.isInteger(32)) {
454	        type_a_stream << "i32";
455	    } else if (type_a.isInteger(8)) {
456	        type_a_stream << "i8";
457	    } else {
458	        type_a_stream << type_a;
459	    }
460	
461	    if (type_c.isF32()) {
462	        type_c_stream << "f32";
463	    } else if (type_c.isF16()) {
464	        type_c_stream << "f16";
465	    } else if (type_c.isInteger(32)) {
466	        type_c_stream << "i32";
467	    } else {
468	        type_c_stream << type_c;
469	    }
470	
471	    // Create GPUOp AMDGPU MFMA operation with config attributes
472	    auto mfma_op = builder.create<cf::AMDGPUMfmaOp>(
473	        location, result_vector_type, a, b, c,
474	        mlir::IntegerAttr::get(builder.getI32Type(), config.m),
475	        mlir::IntegerAttr::get(builder.getI32Type(), config.n),
476	        mlir::IntegerAttr::get(builder.getI32Type(), config.k),
477	        mlir::StringAttr::get(builder.getContext(), type_a_str),
478	        mlir::StringAttr::get(builder.getContext(), type_c_str));
479	
480	    return mfma_op.getResult();
481	}
