508	mlir::Value AMDGPUIntrinsic::CreateRawBufferLoadX1LdsFunction(
509	    ast::Call *call_expr, GeneratorContext *ctx,
510	    llvm::ArrayRef<mlir::Value> resolved_args) const {
511	    auto &builder = ctx->GetCurrentFunctionGenerator()->GetBuilder();
512	    auto location = builder.getUnknownLoc();
513	    auto size = ConstantFolder::FoldIntValue(resolved_args[2]);
514	    auto aux = ConstantFolder::FoldIntValue(resolved_args[6]);
515	
516	    if (!size || *size != 4 || !aux || *aux != 0) {
517	        ctx->diagnostic_manager->Report(basic::DiagnosticCode::kUnimplemented,
518	                                        call_expr->GetSourceRange().getBegin())
519	            << "raw_buffer_load_x1_lds currently requires compile-time "
520	               "size=4 and aux=0";
521	        return nullptr;
522	    }
523	
524	    auto ldsPtr =
525	        builder.create<cf::SubstrateMemRefExtractAlignedPointerAsIndexOp>(
526	            location, builder.getIndexType(), resolved_args[1]);
527	    auto rawOffset = ConvertToIndex(builder, location, resolved_args[5]);
528	    auto ldsPtrWithOffset =
529	        builder.create<mlir::arith::AddIOp>(location, ldsPtr, rawOffset);
530	
531	    auto funcName = intrinsics::MakeIntrinsicFuncName(
532	        "amdgpu", "llvm_amdgcn_raw_buffer_load_lds_u32");
533	    builder.create<mlir::func::CallOp>(
534	        location, funcName, mlir::TypeRange{},
535	        mlir::ValueRange{resolved_args[0], ldsPtrWithOffset,
536	                         ConvertToI32(builder, location, resolved_args[3]),
537	                         ConvertToI32(builder, location, resolved_args[4])});
538	
539	    return ctx->GetCurrentFunctionGenerator()
540	        ->GetExprGenerator()
541	        ->CreateVoidValue();
542	}
