565	mlir::Value AMDGPUIntrinsic::CreateMakeRsrcFunction(
566	    ast::Call *call_expr, GeneratorContext *ctx,
567	    llvm::ArrayRef<mlir::Value> resolved_args) const {
568	    auto &builder = ctx->GetCurrentFunctionGenerator()->GetBuilder();
569	    auto location = GetCallLocation(ctx, call_expr);
570	
571	    auto memref = resolved_args[0];
572	    auto rangeValue = resolved_args[1];
573	
574	    auto ptrIndex =
575	        builder.create<cf::SubstrateMemRefExtractAlignedPointerAsIndexOp>(
576	            location, builder.getIndexType(), memref);
577	    auto ptrI64 = builder.create<mlir::arith::IndexCastOp>(
578	        location, builder.getI64Type(), ptrIndex);
579	
580	    auto shiftAmount =
581	        builder.create<mlir::arith::ConstantIntOp>(location, 32, 64);
582	    auto ptrHighI64 =
583	        builder.create<mlir::arith::ShRUIOp>(location, ptrI64, shiftAmount);
584	    auto ptrLowI32 = builder.create<mlir::arith::TruncIOp>(
585	        location, builder.getI32Type(), ptrI64);
586	    auto ptrHighI32 = builder.create<mlir::arith::TruncIOp>(
587	        location, builder.getI32Type(), ptrHighI64);
588	    mlir::Value rangeI32 = rangeValue;
589	    if (rangeI32.getType().isIndex()) {
590	        rangeI32 = builder.create<mlir::arith::IndexCastOp>(
591	            location, builder.getI32Type(), rangeI32);
592	    } else if (auto intType =
593	                   mlir::dyn_cast<mlir::IntegerType>(rangeI32.getType())) {
594	        if (intType.getWidth() < 32) {
595	            rangeI32 = builder.create<mlir::arith::ExtUIOp>(
596	                location, builder.getI32Type(), rangeI32);
597	        } else if (intType.getWidth() > 32) {
598	            rangeI32 = builder.create<mlir::arith::TruncIOp>(
599	                location, builder.getI32Type(), rangeI32);
600	        }
601	    }
602	    auto configI32 = builder.create<mlir::arith::ConstantIntOp>(
603	        location, kDataFormatU32Config, 32);
604	
605	    auto rsrcType = mlir::VectorType::get({4}, builder.getI32Type());
606	    auto zeroAttr = builder.getIntegerAttr(builder.getI32Type(), 0);
607	    auto zeroRsrcAttr = mlir::DenseElementsAttr::get(rsrcType, zeroAttr);
608	    mlir::Value rsrc = builder.create<mlir::arith::ConstantOp>(
609	        location, rsrcType, zeroRsrcAttr);
610	
611	    rsrc = builder.create<mlir::vector::InsertOp>(
612	        location, ptrLowI32, rsrc,
613	        llvm::SmallVector<mlir::OpFoldResult>{builder.getI64IntegerAttr(0)});
614	    rsrc = builder.create<mlir::vector::InsertOp>(
615	        location, ptrHighI32, rsrc,
616	        llvm::SmallVector<mlir::OpFoldResult>{builder.getI64IntegerAttr(1)});
617	    rsrc = builder.create<mlir::vector::InsertOp>(
618	        location, rangeI32, rsrc,
619	        llvm::SmallVector<mlir::OpFoldResult>{builder.getI64IntegerAttr(2)});
620	    rsrc = builder.create<mlir::vector::InsertOp>(
621	        location, configI32, rsrc,
622	        llvm::SmallVector<mlir::OpFoldResult>{builder.getI64IntegerAttr(3)});
623	
624	    return rsrc;
625	}
