639	mlir::Value AMDGPUIntrinsic::CreateSWaitcntFunction(
640	    ast::Call *call_expr, GeneratorContext *ctx,
641	    llvm::ArrayRef<mlir::Value> resolved_args) const {
642	    auto &builder = ctx->GetCurrentFunctionGenerator()->GetBuilder();
643	    auto location = GetCallLocation(ctx, call_expr);
644	    auto vmcnt = ConstantFolder::FoldIntValue(resolved_args[0]);
645	    auto expcnt = ConstantFolder::FoldIntValue(resolved_args[1]);
646	    auto lgkmcnt = ConstantFolder::FoldIntValue(resolved_args[2]);
647	
648	    auto is_valid = [](std::optional<int64_t> value, int64_t max) {
649	        return value && *value >= 0 && *value <= max;
650	    };
651	
652	    if (!is_valid(vmcnt, 63) || !is_valid(expcnt, 7) ||
653	        !is_valid(lgkmcnt, 15)) {
654	        ctx->diagnostic_manager->Report(basic::DiagnosticCode::kUnimplemented,
655	                                        call_expr->GetSourceRange().getBegin())
656	            << "s_waitcnt(vmcnt, expcnt, lgkmcnt) requires compile-time "
657	               "integer arguments in ranges vmcnt=[0,63], expcnt=[0,7], "
658	               "lgkmcnt=[0,15]";
659	        return nullptr;
660	    }
661	
662	    auto vmcntU = static_cast<uint32_t>(*vmcnt);
663	    auto waitcntValue = ((vmcntU & 48u) << 10) |
664	                        ((static_cast<uint32_t>(*lgkmcnt) & 15u) << 8) |
665	                        ((static_cast<uint32_t>(*expcnt) & 7u) << 4) |
666	                        (vmcntU & 15u);
667	    auto waitcntAttr =
668	        mlir::IntegerAttr::get(builder.getI32Type(), waitcntValue);
669	    builder.create<mlir::ROCDL::WaitcntOp>(location, waitcntAttr);
670	    return ctx->GetCurrentFunctionGenerator()
671	        ->GetExprGenerator()
672	        ->CreateVoidValue();
673	}
