687	mlir::Value AMDGPUIntrinsic::CreateSchedGroupBarrierFunction(
688	    ast::Call *call_expr, GeneratorContext *ctx,
689	    llvm::ArrayRef<mlir::Value> resolved_args) const {
690	    auto &builder = ctx->GetCurrentFunctionGenerator()->GetBuilder();
691	    auto location = GetCallLocation(ctx, call_expr);
692	
693	    auto mask = ConstantFolder::FoldIntValue(resolved_args[0]);
694	    auto size = ConstantFolder::FoldIntValue(resolved_args[1]);
695	    auto group_id = ConstantFolder::FoldIntValue(resolved_args[2]);
696	
697	    auto is_valid_u32 = [](std::optional<int64_t> value) {
698	        return value && *value >= 0 &&
699	               static_cast<uint64_t>(*value) <=
700	                   static_cast<uint64_t>(std::numeric_limits<uint32_t>::max());
701	    };
702	
703	    if (!is_valid_u32(mask) || !is_valid_u32(size) || !is_valid_u32(group_id)) {
704	        ctx->diagnostic_manager->Report(basic::DiagnosticCode::kUnimplemented,
705	                                        call_expr->GetSourceRange().getBegin())
706	            << "sched_group_barrier(mask, size, group_id) requires compile-"
707	               "time non-negative integer arguments <= 2^32-1";
708	        return nullptr;
709	    }
710	
711	    builder.create<mlir::ROCDL::SchedGroupBarrier>(
712	        location, static_cast<uint32_t>(*mask), static_cast<uint32_t>(*size),
713	        static_cast<uint32_t>(*group_id));
714	
715	    return ctx->GetCurrentFunctionGenerator()
716	        ->GetExprGenerator()
717	        ->CreateVoidValue();
718	}
