720	mlir::Value AMDGPUIntrinsic::CreateGenericRawBufferLoadFunction(
721	    ast::Call *call_expr, GeneratorContext *ctx,
722	    llvm::ArrayRef<mlir::Value> resolved_args, int width) const {
723	    auto &builder = ctx->GetCurrentFunctionGenerator()->GetBuilder();
724	    auto location = GetCallLocation(ctx, call_expr);
725	
726	    auto rsrc = resolved_args[0];
727	    auto vindex = resolved_args[1];
728	    auto soffset = resolved_args[2];
729	    auto aux = resolved_args[3];
730	
731	    mlir::Type result_type;
732	    if (width == 1) {
733	        result_type = builder.getI32Type();
734	    } else if (width == 2) {
735	        result_type = mlir::VectorType::get({2}, builder.getI32Type());
736	    } else if (width == 4) {
737	        result_type = mlir::VectorType::get({4}, builder.getI32Type());
738	    } else {
739	        llvm_unreachable("Unsupported raw_buffer_load width");
