static llvm::StringRef GetAmdgpuIntrinsicLibrary() {
    auto *start =
        reinterpret_cast<const char *>(_binary_amdgpu_intrinsics_mlirbc_start);
    auto *end =
        reinterpret_cast<const char *>(_binary_amdgpu_intrinsics_mlirbc_end);
