    AddFunction(
        "s_waitcnt",
        [this](ast::Call *call_expr, GeneratorContext *gen_ctx,
               llvm::ArrayRef<mlir::Value> resolved_args) -> mlir::Value {
            return CreateSWaitcntFunction(call_expr, gen_ctx, resolved_args);
