bool AMDGPUIntrinsic::CheckRawBufferAtomicFAddFunction(
    ast::Call *call_expr, GeneratorContext *ctx,
    llvm::ArrayRef<mlir::Value> resolved_args) const {
    if (resolved_args.size() != 5) {
        ctx->diagnostic_manager->Report(basic::DiagnosticCode::kUnimplemented,
                                        call_expr->GetSourceRange().getBegin())
            << "buffer_atomic_add_f32 requires exactly 5 arguments: "
               "vdata, rsrc, offset, soffset, aux";
        return false;
    }

    if (!resolved_args[0] || !resolved_args[1] || !resolved_args[2] ||
        !resolved_args[3] || !resolved_args[4]) {
        ctx->diagnostic_manager->Report(basic::DiagnosticCode::kUnimplemented,
                                        call_expr->GetSourceRange().getBegin())
            << "Failed to generate operands for buffer_atomic_add_f32";
        return false;
    }

    auto rsrc_type = resolved_args[1].getType();
    auto rsrc_vector = mlir::dyn_cast<mlir::VectorType>(rsrc_type);
    if (!rsrc_vector || rsrc_vector.getNumElements() != 4 ||
        !rsrc_vector.getElementType().isInteger(32)) {
        ctx->diagnostic_manager->Report(basic::DiagnosticCode::kUnimplemented,
                                        call_expr->GetSourceRange().getBegin())
            << "buffer_atomic_add_f32 expects rsrc to be vector<4xi32>";
        return false;
    }

    auto vdata_type = resolved_args[0].getType();
    if (!vdata_type.isF32()) {
        ctx->diagnostic_manager->Report(basic::DiagnosticCode::kUnimplemented,
                                        call_expr->GetSourceRange().getBegin())
            << "buffer_atomic_add_f32 expects vdata to be f32 type";
        return false;
    }

    return true;
}

